import { useState, useRef, useEffect, useCallback } from 'react';
import {
  Type, Upload, Shapes, RotateCcw, ShoppingCart, Check,
  Bold, Italic, AlignLeft, AlignCenter, AlignRight,
  Trash2, Copy, MoveUp, MoveDown, ZoomIn, ZoomOut,
  ChevronDown, ChevronRight, Layers, Sparkles,
  RotateCw, FlipHorizontal, Minus, Plus, Palette,
  Search, Crown, Lock, X, ChevronLeft, ChevronRight as ChevronRightIcon,
} from 'lucide-react';
import { useCart } from '../context/AppContext';
import { MOCK_PRODUCTS } from '../utils/constants';

// ─────────────────────────────────────────────────────────────────────────────
// PRODUCTS
// ─────────────────────────────────────────────────────────────────────────────
const PRODUCTS = [
  { id: 1, name: 'T-Shirt',   price: 10000, sizes: ['XS','S','M','L','XL','XXL'] },
  { id: 2, name: 'Sweat',     price: 15000, sizes: ['S','M','L','XL','XXL'] },
  { id: 3, name: 'Hoodie',    price: 18000, sizes: ['S','M','L','XL','XXL'] },
  { id: 4, name: 'Pantalon',  price: 14000, sizes: ['XS','S','M','L','XL','XXL'] },
  { id: 5, name: 'Sneakers',  price: 25000, sizes: ['38','39','40','41','42','43','44','45'] },
  { id: 6, name: 'Casquette', price: 7000,  sizes: ['Unique'] },
];

// ─────────────────────────────────────────────────────────────────────────────
// COLORS
// ─────────────────────────────────────────────────────────────────────────────
const PRODUCT_COLORS = [
  { hex: '#FFFFFF', name: 'Blanc' },
  { hex: '#1C1C1C', name: 'Noir' },
  { hex: '#1D4ED8', name: 'Bleu' },
  { hex: '#DC2626', name: 'Rouge' },
  { hex: '#16A34A', name: 'Vert' },
  { hex: '#D97706', name: 'Orange' },
  { hex: '#7C3AED', name: 'Violet' },
  { hex: '#DB2777', name: 'Rose' },
  { hex: '#0891B2', name: 'Cyan' },
  { hex: '#92400E', name: 'Marron' },
  { hex: '#6B7280', name: 'Gris' },
  { hex: '#F9A8D4', name: 'Rose pâle' },
];

// ─────────────────────────────────────────────────────────────────────────────
// MOCKUP DATA  (simule ce que Supabase retournerait)
//
//  Chaque produit a des "views" : front / back / sleeve / detail / left / right
//  url        → vrai PNG blanc/gris clair uploadé sur Supabase Storage
//              (ici on utilise des placeholders haute qualité de Unsplash /
//               des services de mockup gratuits en blanc)
//  colorOverlay → true = on applique mix-blend-mode multiply pour la couleur
//  colorVariants → map hex→url si l'admin a uploadé des variantes colorées
// ─────────────────────────────────────────────────────────────────────────────
const MOCKUP_DATA = {
  1: { // T-Shirt
    views: [
      { id: 'front', label: 'Avant',   icon: '👕', url: 'https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'back',  label: 'Dos',     icon: '🔄', url: 'https://images.unsplash.com/photo-1503342217505-b0a15ec3261c?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'detail',label: 'Détail',  icon: '🔍', url: 'https://images.unsplash.com/photo-1618354691373-d851c5c3a990?w=600&q=80&fit=crop', colorOverlay: true },
    ],
    printArea: { top: '18%', left: '28%', width: '44%', height: '38%' },
  },
  2: { // Sweat
    views: [
      { id: 'front', label: 'Avant',   icon: '👕', url: 'https://images.unsplash.com/photo-1556821840-3a63f15732ce?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'back',  label: 'Dos',     icon: '🔄', url: 'https://images.unsplash.com/photo-1578768079052-aa76e52ff9ef?w=600&q=80&fit=crop', colorOverlay: true },
    ],
    printArea: { top: '16%', left: '27%', width: '46%', height: '40%' },
  },
  3: { // Hoodie
    views: [
      { id: 'front',  label: 'Avant',   icon: '👕', url: 'https://images.unsplash.com/photo-1509942774463-acf339cf87d5?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'back',   label: 'Dos',     icon: '🔄', url: 'https://images.unsplash.com/photo-1542327897-d73f4005b533?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'sleeve', label: 'Manche',  icon: '💪', url: 'https://images.unsplash.com/photo-1604644401890-0bd678c83788?w=600&q=80&fit=crop', colorOverlay: true },
    ],
    printArea: { top: '20%', left: '28%', width: '44%', height: '36%' },
  },
  4: { // Pantalon
    views: [
      { id: 'front', label: 'Avant',  icon: '👖', url: 'https://images.unsplash.com/photo-1541099649105-f69ad21f3246?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'back',  label: 'Dos',    icon: '🔄', url: 'https://images.unsplash.com/photo-1542272604-787c3835535d?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'left',  label: 'Côté G', icon: '◀', url: 'https://images.unsplash.com/photo-1624378439575-d8705ad7ae80?w=600&q=80&fit=crop', colorOverlay: true },
    ],
    printArea: { top: '10%', left: '24%', width: '52%', height: '50%' },
  },
  5: { // Sneakers
    views: [
      { id: 'side',  label: 'Côté',   icon: '👟', url: 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'top',   label: 'Dessus', icon: '⬆️', url: 'https://images.unsplash.com/photo-1595950653106-6c9ebd614d3a?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'back',  label: 'Talon',  icon: '🔄', url: 'https://images.unsplash.com/photo-1584735175315-9d5df23be620?w=600&q=80&fit=crop', colorOverlay: true },
    ],
    printArea: { top: '22%', left: '20%', width: '56%', height: '40%' },
  },
  6: { // Casquette
    views: [
      { id: 'front', label: 'Avant',  icon: '🧢', url: 'https://images.unsplash.com/photo-1588850561407-ed78c282e89b?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'side',  label: 'Côté',   icon: '↔️', url: 'https://images.unsplash.com/photo-1534215754734-18e55d13e346?w=600&q=80&fit=crop', colorOverlay: true },
      { id: 'back',  label: 'Dos',    icon: '🔄', url: 'https://images.unsplash.com/photo-1576871337622-98d48d1cf531?w=600&q=80&fit=crop', colorOverlay: true },
    ],
    printArea: { top: '15%', left: '30%', width: '40%', height: '42%' },
  },
};

// ─────────────────────────────────────────────────────────────────────────────
// ELEMENT LIBRARY  (simule la table Supabase `library_elements`)
//
//  Quand tu branches Supabase, tu remplaceras MOCK_ELEMENTS par :
//    const { data } = await supabase.from('library_elements').select('*')
//      .ilike('name', `%${query}%`).eq('category', activeCategory)
//
//  Schéma Supabase :
//    library_elements(id, name, category, tags text[], url, thumbnail_url,
//                     is_pro bool, created_at)
//    library_categories(id, slug, label, icon, order)
// ─────────────────────────────────────────────────────────────────────────────
const ELEMENT_CATEGORIES = [
  { slug: 'all',        label: 'Tout',         icon: '✦' },
  { slug: 'stickers',   label: 'Stickers',     icon: '🔥' },
  { slug: 'streetwear', label: 'Streetwear',   icon: '👑' },
  { slug: 'afroart',    label: 'Afro Art',     icon: '🌍' },
  { slug: 'nature',     label: 'Nature',       icon: '🌿' },
  { slug: 'typo',       label: 'Typo art',     icon: '✍️' },
  { slug: 'abstract',   label: 'Abstract',     icon: '◈' },
  { slug: 'vintage',    label: 'Vintage',      icon: '📻' },
];

// Placeholder illustrations (simulées — l'admin uploaderait de vrais PNG/SVG)
// On génère des thumbnails visuellement différents avec des SVG data URLs
const makeSvgThumb = (shape, color1, color2, label) => {
  const shapes = {
    bolt: `<polygon points="60,5 30,55 52,55 40,95 70,45 48,45" fill="${color1}"/>`,
    flame: `<path d="M50,95 C20,95 10,70 25,50 C15,55 12,40 20,30 C25,40 30,38 28,25 C40,35 38,50 45,45 C40,35 48,20 55,10 C55,30 65,35 62,50 C70,40 72,55 65,60 C80,45 78,75 50,95Z" fill="${color1}"/>`,
    crown: `<path d="M10,70 L20,30 L40,55 L50,10 L60,55 L80,30 L90,70 L10,70Z" fill="${color1}"/><circle cx="50" cy="10" r="6" fill="${color2}"/><circle cx="20" cy="30" r="5" fill="${color2}"/><circle cx="80" cy="30" r="5" fill="${color2}"/>`,
    star: `<polygon points="50,5 61,35 95,35 68,57 79,91 50,70 21,91 32,57 5,35 39,35" fill="${color1}"/>`,
    diamond: `<polygon points="50,5 92,50 50,95 8,50" fill="${color1}"/><polygon points="50,20 78,50 50,80 22,50" fill="${color2}" opacity="0.5"/>`,
    eye: `<ellipse cx="50" cy="50" rx="44" ry="28" fill="${color1}"/><circle cx="50" cy="50" r="16" fill="white"/><circle cx="50" cy="50" r="9" fill="${color1}"/><circle cx="55" cy="45" r="3" fill="white"/>`,
    wave: `<path d="M5,60 C20,30 35,30 50,60 C65,90 80,90 95,60" fill="none" stroke="${color1}" stroke-width="10" stroke-linecap="round"/><path d="M5,40 C20,10 35,10 50,40 C65,70 80,70 95,40" fill="none" stroke="${color2}" stroke-width="10" stroke-linecap="round" opacity="0.6"/>`,
