// ─────────────────────────────────────────────────────────────────────────────
// PHOTO MOCKUP COMPONENT
// Technique : img base + calque couleur en mix-blend-mode: multiply
// → le blanc du mockup devient la couleur choisie, les ombres/plis restent
// ─────────────────────────────────────────────────────────────────────────────
function PhotoMockup({ productId, viewId, productColor }) {
  const productData = MOCKUP_DATA[productId];
  if (!productData) return null;

  const view = productData.views.find(v => v.id === viewId) || productData.views[0];

  // On convertit hex → rgba pour le multiply overlay
  // multiply blanc + couleur = couleur / multiply gris + couleur = couleur foncée ✓
  return (
    <div style={{ position: 'relative', width: '100%', height: '100%', borderRadius: 12, overflow: 'hidden' }}>
      {/* Image de base */}
      <img
        src={view.url}
        alt={view.label}
        style={{
          width: '100%',
          height: '100%',
          objectFit: 'cover',
          display: 'block',
          borderRadius: 12,
        }}
        crossOrigin="anonymous"
      />
      {/* Calque couleur overlay — mix-blend-mode: multiply */}
      {view.colorOverlay && productColor !== '#FFFFFF' && (
        <div style={{
          position: 'absolute',
          inset: 0,
          background: productColor,
          mixBlendMode: 'multiply',
          borderRadius: 12,
          opacity: 0.72,
          pointerEvents: 'none',
        }} />
      )}
    </div>
  );
}

